import {
  isSameDay,
  isSameHour,
  isSameMinute,
  isSameMonth,
  isSameYear,
} from 'date-fns';

import { formatDate } from '@dynatrace-sdk/units';

import { formatDateTicks } from '../../../../../utils/format-date-ticks.js';
import {
  formatWeekday,
  formatYear,
} from '../../../../../utils/format-dates.js';

const shouldIncludeSeconds = (date: Date): boolean => date.getSeconds() !== 0;

const createFullDateTimeFormatOptions = (includeSeconds: boolean) => ({
  day: '2-digit' as const,
  month: 'short' as const,
  year: 'numeric' as const,
  hour: '2-digit' as const,
  minute: '2-digit' as const,
  second: includeSeconds ? ('numeric' as const) : undefined,
});

const formatRange = (from: string, to: string, prefix?: string): string => {
  const base = `${from} - ${to}`;
  return prefix ? `${prefix}, ${base}` : base;
};

const formatTimeRange = (from: Date, to: Date): string => {
  return formatRange(formatDateTicks(from), formatDateTicks(to));
};

const formatMinuteRange = (from: Date, to: Date): string => {
  const commonDate = formatDate(from, {
    month: 'short',
    day: '2-digit',
    year: 'numeric',
  });
  const fromTime = formatDate(from, { hour: '2-digit', minute: '2-digit' });
  const toTime = formatDate(to, { hour: '2-digit', minute: '2-digit' });
  return formatRange(fromTime, toTime, commonDate);
};

const formatHourRange = (from: Date, to: Date): string => {
  const commonDay = formatDate(from, {
    day: '2-digit',
    month: 'short',
    year: 'numeric',
  });
  const fromHour = formatDate(from, { hour: '2-digit' });
  const toHour = formatDate(to, { hour: '2-digit' });
  return formatRange(fromHour, toHour, commonDay);
};

const formatDayRange = (from: Date, to: Date): string => {
  const commonMonth = formatDate(from, {
    month: 'short',
    year: 'numeric',
  });
  const fromDay = formatDate(from, { day: '2-digit' });
  const toDay = formatDate(to, { day: '2-digit' });
  return formatRange(fromDay, toDay, commonMonth);
};

const formatYearRange = (from: Date, to: Date): string => {
  const commonYear = formatYear(from.getTime());
  const fromWeekday = formatWeekday(from.getTime());
  const toWeekday = formatWeekday(to.getTime());
  return formatRange(fromWeekday, toWeekday, commonYear);
};

export const formatDateRange = (from: Date, to: Date): string => {
  if (isSameMinute(from, to)) {
    return formatTimeRange(from, to);
  }
  if (isSameHour(from, to)) {
    return formatMinuteRange(from, to);
  }
  if (isSameDay(from, to)) {
    return formatHourRange(from, to);
  }
  if (isSameMonth(from, to)) {
    return formatDayRange(from, to);
  }
  if (isSameYear(from, to)) {
    return formatYearRange(from, to);
  }

  const fromFull = formatDate(
    from,
    createFullDateTimeFormatOptions(shouldIncludeSeconds(from)),
  );
  const toFull = formatDate(
    to,
    createFullDateTimeFormatOptions(shouldIncludeSeconds(to)),
  );
  return formatRange(fromFull, toFull);
};
